// DB wraps the database connection pool and provides store methods
type DB struct {
	pool    *pgxpool.Pool
	queries Querier
}

// Querier interface for database operations (will be generated by sqlc)
type Querier interface {
	// User operations
	CreateUser(ctx context.Context, params CreateUserParams) (*User, error)
	GetUserByID(ctx context.Context, id uuid.UUID) (*User, error)
	GetUserByClerkID(ctx context.Context, clerkUserID string) (*User, error)
	GetUserByAPIKey(ctx context.Context, apiKey string) (*User, error)
	UpdateUserTier(ctx context.Context, params UpdateUserTierParams) (*User, error)
	UpdateUserAPIKey(ctx context.Context, params UpdateUserAPIKeyParams) (*User, error)
	DeleteUser(ctx context.Context, id uuid.UUID) error

	// Scan job operations
	CreateScanJob(ctx context.Context, params CreateScanJobParams) (*ScanJob, error)
	GetScanJobByID(ctx context.Context, id uuid.UUID) (*ScanJob, error)
	ListScanJobsByUser(ctx context.Context, params ListScanJobsParams) ([]ScanJob, error)
	CountScanJobsByUser(ctx context.Context, userID uuid.UUID) (int64, error)
	ListScanJobsByUserAndStatus(ctx context.Context, params ListScanJobsByStatusParams) ([]ScanJob, error)
	ListRecentScanJobsByUser(ctx context.Context, params ListRecentScansParams) ([]ScanJob, error)
	UpdateScanJobStatus(ctx context.Context, params UpdateScanJobStatusParams) (*ScanJob, error)
	UpdateScanJobStarted(ctx context.Context, id uuid.UUID) (*ScanJob, error)
	UpdateScanJobCompleted(ctx context.Context, params UpdateScanJobCompletedParams) (*ScanJob, error)
	UpdateScanJobFailed(ctx context.Context, id uuid.UUID) (*ScanJob, error)
	UpdateScanJobAuthConfirmed(ctx context.Context, params UpdateAuthParams) (*ScanJob, error)
	DeleteScanJob(ctx context.Context, id uuid.UUID) error

	// Finding operations
	CreateFinding(ctx context.Context, params CreateFindingParams) (*Finding, error)
	GetFindingByID(ctx context.Context, id uuid.UUID) (*Finding, error)
	ListFindingsByScanJob(ctx context.Context, params ListFindingsParams) ([]Finding, error)
	ListFindingsByScanJobAndSeverity(ctx context.Context, params ListFindingsBySeverityParams) ([]Finding, error)
	CountFindingsByScanJob(ctx context.Context, scanJobID uuid.UUID) (int64, error)
	CountFindingsBySeverity(ctx context.Context, scanJobID uuid.UUID) ([]SeverityCount, error)
	UpdateFinding(ctx context.Context, params UpdateFindingParams) (*Finding, error)
	DeleteFinding(ctx context.Context, id uuid.UUID) error

	// Report operations
	CreateReport(ctx context.Context, params CreateReportParams) (*Report, error)
	GetReportByID(ctx context.Context, id uuid.UUID) (*Report, error)
	GetReportByScanJobID(ctx context.Context, scanJobID uuid.UUID) (*Report, error)
	GetReportByShareToken(ctx context.Context, shareToken string) (*Report, error)
	ListReportsByUser(ctx context.Context, params ListReportsParams) ([]Report, error)
	UpdateReportShareToken(ctx context.Context, params UpdateShareParams) (*Report, error)
	RevokeReportShare(ctx context.Context, id uuid.UUID) (*Report, error)
	DeleteReport(ctx context.Context, id uuid.UUID) error

	// Dashboard analytics
	GetUserScanStats(ctx context.Context, userID uuid.UUID) (*UserScanStats, error)
	GetUserFindingStats(ctx context.Context, userID uuid.UUID) (*UserFindingStats, error)
	GetScansTrendOverTime(ctx context.Context, userID uuid.UUID) ([]ScanTrend, error)
	GetFindingsByCategoryStats(ctx context.Context, userID uuid.UUID) ([]CategoryStat, error)
	GetTopTargets(ctx context.Context, userID uuid.UUID, limit int32) ([]TopTarget, error)

	// Dashboard Phase 15
	GetScanStatistics(ctx context.Context, userID uuid.UUID) (*ScanStatistics, error)
	GetFindingsBySeverityStats(ctx context.Context, userID uuid.UUID) (*FindingSeverityStats, error)
	GetScanActivity(ctx context.Context, userID uuid.UUID, limit, offset int32) ([]ScanActivity, int64, error)
	GetVulnerabilityTrends(ctx context.Context, userID uuid.UUID, days int, startDate, endDate *time.Time) ([]VulnerabilityTrend, error)
	GetMostScannedTargets(ctx context.Context, userID uuid.UUID, limit int32) ([]TargetStats, int64, error)

	// History Phase 15
	GetScanHistory(ctx context.Context, filter HistoryFilter) ([]*ScanJobWithStats, int64, error)
	GetTargetScanHistory(ctx context.Context, userID uuid.UUID, target string, limit, offset int32) ([]*ScanJobWithStats, int64, error)

	// Diff Phase 15
	GetScanFindingsForDiff(ctx context.Context, scanJobID uuid.UUID) ([]*FindingForDiff, error)

	// Search
	SearchScans(ctx context.Context, params SearchParams) ([]ScanJob, error)
	SearchFindings(ctx context.Context, params SearchParams) ([]Finding, error)
}

// TxStore wraps database queries within a transaction
type TxStore struct {
	queries Querier
	tx      pgx.Tx
}

// NewDB creates a new database connection pool
func NewDB(connString string) (*DB, error) {
	// Configure connection pool
	config, err := pgxpool.ParseConfig(connString)
	if err != nil {
		return nil, fmt.Errorf("failed to parse connection string: %w", err)
	}

	// Set pool configuration
	config.MaxConns = 25
	config.MinConns = 5
	config.MaxConnLifetime = time.Hour
	config.MaxConnIdleTime = 30 * time.Minute
	config.HealthCheckPeriod = 5 * time.Minute

	// Create connection pool
	pool, err := pgxpool.NewWithConfig(context.Background(), config)
	if err != nil {
		return nil, fmt.Errorf("failed to create connection pool: %w", err)
	}

	// Verify connection
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := pool.Ping(ctx); err != nil {
		pool.Close()
		return nil, fmt.Errorf("failed to ping database: %w", err)
	}

	return &DB{
		pool: pool,
	}, nil
}

// Close closes the database connection pool
func (d *DB) Close() {
	if d.pool != nil {
		d.pool.Close()
	}
}

// Ping checks database connectivity
func (d *DB) Ping(ctx context.Context) error {
	return d.pool.Ping(ctx)
}

// Pool returns the underlying connection pool
func (d *DB) Pool() *pgxpool.Pool {
	return d.pool
}

// BeginTx starts a new database transaction
func (d *DB) BeginTx(ctx context.Context) (*TxStore, error) {
	tx, err := d.pool.Begin(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to begin transaction: %w", err)
	}

	return &TxStore{
		tx: tx,
	}, nil
}

// Commit commits the transaction
func (tx *TxStore) Commit(ctx context.Context) error {
	return tx.tx.Commit(ctx)
}

// Rollback rolls back the transaction
func (tx *TxStore) Rollback(ctx context.Context) error {
	return tx.tx.Rollback(ctx)
}

// SetUserContext sets the RLS context for the current user
func (d *DB) SetUserContext(ctx context.Context, clerkUserID string, userUUID uuid.UUID) error {
	_, err := d.pool.Exec(ctx, "SELECT set_config('app.current_user_id', $1, true)", clerkUserID)
	if err != nil {
		return fmt.Errorf("failed to set user context: %w", err)
	}

	_, err = d.pool.Exec(ctx, "SELECT set_config('app.current_user_uuid', $1, true)", userUUID.String())
	if err != nil {
		return fmt.Errorf("failed to set user UUID context: %w", err)
	}

	return nil
}

// Exec executes a raw SQL query
func (d *DB) Exec(ctx context.Context, sql string, args ...interface{}) error {
	_, err := d.pool.Exec(ctx, sql, args...)
	return err
}

// QueryRow executes a raw SQL query and scans a single row
func (d *DB) QueryRow(ctx context.Context, sql string, args ...interface{}) pgx.Row {
	return d.pool.QueryRow(ctx, sql, args...)
}

