// =============================================================================
// Type Conversions for pgx
// =============================================================================

// Scan implements pgtype.Scanner for Numeric
func (f *Finding) ScanCVSS(src interface{}) error {
	if src == nil {
		f.CVSSScore = 0
		return nil
	}
	var num pgtype.Numeric
	if err := num.Scan(src); err != nil {
		return err
	}
	// Convert numeric to float64 using Int and Exp
	if num.NaN || num.InfinityModifier != 0 {
		f.CVSSScore = 0
		return nil
	}
	// Convert to float64: value = Int * 10^(-Exp)
	floatVal := float64(num.Int.Int64())
	for i := 0; i < int(num.Exp); i++ {
		floatVal *= 10
	}
	for i := 0; i < int(-num.Exp); i++ {
		floatVal /= 10
	}
	f.CVSSScore = floatVal
	return nil
}

