// GetScanStatistics retrieves aggregated scan statistics for a user
func (d *DB) GetScanStatistics(ctx context.Context, userID uuid.UUID) (*ScanStatistics, error) {
	query := `
		SELECT 
			COUNT(*) as total_scans,
			COUNT(*) FILTER (WHERE status = 'completed') as completed_scans,
			COUNT(*) FILTER (WHERE status = 'failed') as failed_scans,
			COUNT(*) FILTER (WHERE status IN ('pending', 'queued', 'running')) as active_scans,
			COUNT(*) FILTER (WHERE created_at > DATE_TRUNC('month', NOW())) as scans_this_month,
			COALESCE(AVG(EXTRACT(EPOCH FROM (completed_at - started_at))) FILTER (WHERE completed_at IS NOT NULL AND started_at IS NOT NULL), 0) as avg_duration_seconds,
			MAX(created_at) as last_scan_at
		FROM scan_jobs
		WHERE user_id = $1
	`

	var stats ScanStatistics
	var lastScanAt *time.Time

	err := d.pool.QueryRow(ctx, query, userID).Scan(
		&stats.TotalScans,
		&stats.CompletedScans,
		&stats.FailedScans,
		&stats.ActiveScans,
		&stats.ScansThisMonth,
		&stats.AvgDurationSeconds,
		&lastScanAt,
	)
	if err != nil {
		return nil, err
	}

	stats.LastScanAt = lastScanAt
	return &stats, nil
}

