// GetScanActivity retrieves recent scan activity with pagination
func (d *DB) GetScanActivity(ctx context.Context, userID uuid.UUID, limit, offset int32) ([]ScanActivity, int64, error) {
	// Get total count
	var total int64
	countQuery := `SELECT COUNT(*) FROM scan_jobs WHERE user_id = $1`
	if err := d.pool.QueryRow(ctx, countQuery, userID).Scan(&total); err != nil {
		return nil, 0, err
	}

	// Get activities
	query := `
		SELECT 
			sj.id,
			sj.target,
			sj.status,
			COALESCE((SELECT COUNT(*) FROM findings f WHERE f.scan_job_id = sj.id), 0) as findings_count,
			COALESCE(sj.risk_score, 0) / 10.0 as risk_score,
			COALESCE(sj.started_at, sj.created_at) as started_at,
			sj.completed_at
		FROM scan_jobs sj
		WHERE sj.user_id = $1
		ORDER BY sj.created_at DESC
		LIMIT $2 OFFSET $3
	`

	rows, err := d.pool.Query(ctx, query, userID, limit, offset)
	if err != nil {
		return nil, 0, err
	}
	defer rows.Close()

	var activities []ScanActivity
	for rows.Next() {
		var activity ScanActivity
		var completedAt *time.Time
		err := rows.Scan(
			&activity.ID,
			&activity.Target,
			&activity.Status,
			&activity.FindingsCount,
			&activity.RiskScore,
			&activity.StartedAt,
			&completedAt,
		)
		if err != nil {
			continue
		}
		activity.CompletedAt = completedAt
		activities = append(activities, activity)
	}

	return activities, total, rows.Err()
}

// GetVulnerabilityTrends retrieves daily vulnerability counts for trend charts
func (d *DB) GetVulnerabilityTrends(ctx context.Context, userID uuid.UUID, days int, startDate, endDate *time.Time) ([]VulnerabilityTrend, error) {
	// Determine date range
	var start, end time.Time
	if startDate != nil && endDate != nil {
		start = *startDate
		end = *endDate
	} else {
		end = time.Now()
		start = end.AddDate(0, 0, -days)
	}

	query := `
		WITH date_series AS (
			SELECT generate_series($2::date, $3::date, '1 day'::interval)::date as date
		),
		daily_findings AS (
			SELECT 
				DATE(f.created_at) as date,
				COUNT(*) FILTER (WHERE f.severity = 'Critical') as critical,
				COUNT(*) FILTER (WHERE f.severity = 'High') as high,
				COUNT(*) FILTER (WHERE f.severity = 'Medium') as medium,
				COUNT(*) FILTER (WHERE f.severity = 'Low') as low,
				COUNT(*) FILTER (WHERE f.severity = 'Informational') as info
			FROM findings f
			INNER JOIN scan_jobs sj ON f.scan_job_id = sj.id
			WHERE sj.user_id = $1
				AND f.created_at BETWEEN $2 AND $3
			GROUP BY DATE(f.created_at)
		)
		SELECT 
			ds.date::text,
			COALESCE(df.critical, 0) as critical,
			COALESCE(df.high, 0) as high,
			COALESCE(df.medium, 0) as medium,
			COALESCE(df.low, 0) as low,
			COALESCE(df.info, 0) as info
		FROM date_series ds
		LEFT JOIN daily_findings df ON ds.date = df.date
		ORDER BY ds.date ASC
	`

	rows, err := d.pool.Query(ctx, query, userID, start, end)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var trends []VulnerabilityTrend
	for rows.Next() {
		var trend VulnerabilityTrend
		err := rows.Scan(
			&trend.Date,
			&trend.Critical,
			&trend.High,
			&trend.Medium,
			&trend.Low,
			&trend.Info,
		)
		if err != nil {
			continue
		}
		trends = append(trends, trend)
	}

	return trends, rows.Err()
}

// GetMostScannedTargets retrieves the most frequently scanned targets
func (d *DB) GetMostScannedTargets(ctx context.Context, userID uuid.UUID, limit int32) ([]TargetStats, int64, error) {
	// Get total unique targets count
	var total int64
	countQuery := `
		SELECT COUNT(DISTINCT target) 
		FROM scan_jobs 
		WHERE user_id = $1
	`
	if err := d.pool.QueryRow(ctx, countQuery, userID).Scan(&total); err != nil {
		return nil, 0, err
	}

	query := `
		WITH target_stats AS (
			SELECT 
				target,
				COUNT(*) as scan_count,
				MAX(created_at) as last_scanned_at,
				(
					SELECT id FROM scan_jobs 
					WHERE user_id = $1 AND target = sj.target 
					ORDER BY created_at DESC LIMIT 1
				) as last_scan_id,
				(
					SELECT status FROM scan_jobs 
					WHERE user_id = $1 AND target = sj.target 
					ORDER BY created_at DESC LIMIT 1
				) as last_scan_status,
				COALESCE(AVG(risk_score) FILTER (WHERE risk_score > 0), 0) / 10.0 as avg_risk_score
			FROM scan_jobs sj
			WHERE user_id = $1
			GROUP BY target
		)
		SELECT 
			ts.target,
			ts.scan_count,
			ts.last_scanned_at,
			ts.last_scan_id,
			ts.last_scan_status,
			ts.avg_risk_score,
			COALESCE((
				SELECT COUNT(*) 
				FROM findings f 
				WHERE f.scan_job_id = ts.last_scan_id
			), 0) as total_findings
		FROM target_stats ts
		ORDER BY ts.scan_count DESC, ts.last_scanned_at DESC
		LIMIT $2
	`

	rows, err := d.pool.Query(ctx, query, userID, limit)
	if err != nil {
		return nil, 0, err
	}
	defer rows.Close()

	var targets []TargetStats
	for rows.Next() {
		var target TargetStats
		err := rows.Scan(
			&target.Target,
			&target.ScanCount,
			&target.LastScannedAt,
			&target.LastScanID,
			&target.LastScanStatus,
			&target.AvgRiskScore,
			&target.TotalFindings,
		)
		if err != nil {
			continue
		}
		targets = append(targets, target)
	}

	return targets, total, rows.Err()
}

