// GetScanHistory retrieves filtered scan history
func (d *DB) GetScanHistory(ctx context.Context, filter HistoryFilter) ([]*ScanJobWithStats, int64, error) {
	// Build the base query
	whereClause := "WHERE user_id = $1"
	params := []interface{}{filter.UserID}
	paramIndex := 2

	if filter.Status != "" {
		whereClause += fmt.Sprintf(" AND status = $%d", paramIndex)
		params = append(params, filter.Status)
		paramIndex++
	}

	if filter.Target != "" {
		whereClause += fmt.Sprintf(" AND target ILIKE $%d", paramIndex)
		params = append(params, "%"+filter.Target+"%")
		paramIndex++
	}

	if filter.StartDate != nil {
		whereClause += fmt.Sprintf(" AND created_at >= $%d", paramIndex)
		params = append(params, *filter.StartDate)
		paramIndex++
	}

	if filter.EndDate != nil {
		whereClause += fmt.Sprintf(" AND created_at <= $%d", paramIndex)
		params = append(params, *filter.EndDate)
		paramIndex++
	}

	// Get total count
	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM scan_jobs %s", whereClause)
	var total int64
	if err := d.pool.QueryRow(ctx, countQuery, params...).Scan(&total); err != nil {
		return nil, 0, err
	}

	// Determine sort order
	sortBy := "created_at"
	if filter.SortBy != "" {
		sortBy = filter.SortBy
	}
	sortOrder := "DESC"
	if filter.SortOrder == "asc" {
		sortOrder = "ASC"
	}

	// Build main query
	query := fmt.Sprintf(`
		SELECT 
			id, user_id, target, target_type, scope, status, auth_confirmed,
			auth_confirmed_ip, auth_confirmed_at, custom_headers, started_at,
			completed_at, risk_score, finding_counts, created_at,
			COALESCE((SELECT COUNT(*) FROM findings f WHERE f.scan_job_id = sj.id), 0) as total_findings
		FROM scan_jobs sj
		%s
		ORDER BY %s %s
		LIMIT $%d OFFSET $%d
	`, whereClause, sortBy, sortOrder, paramIndex, paramIndex+1)

	params = append(params, filter.Limit, filter.Offset)

	rows, err := d.pool.Query(ctx, query, params...)
	if err != nil {
		return nil, 0, err
	}
	defer rows.Close()

	var jobs []*ScanJobWithStats
	for rows.Next() {
		var job ScanJobWithStats
		err := rows.Scan(
			&job.ID, &job.UserID, &job.Target, &job.TargetType, &job.Scope, &job.Status,
			&job.AuthConfirmed, &job.AuthConfirmedIP, &job.AuthConfirmedAt, &job.CustomHeaders,
			&job.StartedAt, &job.CompletedAt, &job.RiskScore, &job.FindingCounts, &job.CreatedAt,
			&job.TotalFindings,
		)
		if err != nil {
			continue
		}
		jobs = append(jobs, &job)
	}

	return jobs, total, rows.Err()
}

// GetTargetScanHistory retrieves all scans for a specific target
func (d *DB) GetTargetScanHistory(ctx context.Context, userID uuid.UUID, target string, limit, offset int32) ([]*ScanJobWithStats, int64, error) {
	// Get total count
	var total int64
	countQuery := `
		SELECT COUNT(*) FROM scan_jobs 
		WHERE user_id = $1 AND target = $2
	`
	if err := d.pool.QueryRow(ctx, countQuery, userID, target).Scan(&total); err != nil {
		return nil, 0, err
	}

	query := `
		SELECT 
			sj.id, sj.user_id, sj.target, sj.target_type, sj.scope, sj.status,
			sj.auth_confirmed, sj.auth_confirmed_ip, sj.auth_confirmed_at,
			sj.custom_headers, sj.started_at, sj.completed_at, sj.risk_score,
			sj.finding_counts, sj.created_at,
			COALESCE((SELECT COUNT(*) FROM findings f WHERE f.scan_job_id = sj.id), 0) as total_findings
		FROM scan_jobs sj
		WHERE sj.user_id = $1 AND sj.target = $2
		ORDER BY sj.created_at DESC
		LIMIT $3 OFFSET $4
	`

	rows, err := d.pool.Query(ctx, query, userID, target, limit, offset)
	if err != nil {
		return nil, 0, err
	}
	defer rows.Close()

	var jobs []*ScanJobWithStats
	for rows.Next() {
		var job ScanJobWithStats
		err := rows.Scan(
			&job.ID, &job.UserID, &job.Target, &job.TargetType, &job.Scope, &job.Status,
			&job.AuthConfirmed, &job.AuthConfirmedIP, &job.AuthConfirmedAt, &job.CustomHeaders,
			&job.StartedAt, &job.CompletedAt, &job.RiskScore, &job.FindingCounts, &job.CreatedAt,
			&job.TotalFindings,
		)
		if err != nil {
			continue
		}
		jobs = append(jobs, &job)
	}

	return jobs, total, rows.Err()
}

// ============================================================================
// Phase 15: Diff Methods Implementation
// ============================================================================

// GetScanFindingsForDiff retrieves findings for diff comparison
func (d *DB) GetScanFindingsForDiff(ctx context.Context, scanJobID uuid.UUID) ([]*FindingForDiff, error) {
	query := `
		SELECT 
			id, module, category, severity, title, description,
			COALESCE(cvss_score, 0) as cvss_score, COALESCE(remediation, '') as remediation
		FROM findings
		WHERE scan_job_id = $1
		ORDER BY 
			CASE severity
				WHEN 'Critical' THEN 1
				WHEN 'High' THEN 2
				WHEN 'Medium' THEN 3
				WHEN 'Low' THEN 4
				WHEN 'Informational' THEN 5
			END,
			created_at DESC
	`

	rows, err := d.pool.Query(ctx, query, scanJobID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var findings []*FindingForDiff
	for rows.Next() {
		var f FindingForDiff
		err := rows.Scan(
			&f.ID, &f.Module, &f.Category, &f.Severity, &f.Title,
			&f.Description, &f.CVSSScore, &f.Remediation,
		)
		if err != nil {
			continue
		}
		findings = append(findings, &f)
	}

	return findings, rows.Err()
}

