// CreateSubscription creates a new subscription
func (d *DB) CreateSubscription(ctx context.Context, params CreateSubscriptionParams) (*Subscription, error) {
	query := `
		INSERT INTO subscriptions (
			user_id, stripe_customer_id, stripe_subscription_id, tier, status,
			current_period_start, current_period_end
		)
		VALUES ($1, $2, $3, $4, $5, $6, $7)
		ON CONFLICT (stripe_subscription_id) DO UPDATE SET
			status = EXCLUDED.status,
			current_period_start = EXCLUDED.current_period_start,
			current_period_end = EXCLUDED.current_period_end,
			updated_at = NOW()
		RETURNING id, user_id, stripe_customer_id, stripe_subscription_id, tier, status,
		          current_period_start, current_period_end, cancel_at_period_end, canceled_at,
		          created_at, updated_at
	`

	row := d.pool.QueryRow(ctx, query,
		params.UserID, params.StripeCustomerID, params.StripeSubscriptionID,
		params.Tier, params.Status, params.CurrentPeriodStart, params.CurrentPeriodEnd)

	var sub Subscription
	err := row.Scan(
		&sub.ID, &sub.UserID, &sub.StripeCustomerID, &sub.StripeSubscriptionID,
		&sub.Tier, &sub.Status, &sub.CurrentPeriodStart, &sub.CurrentPeriodEnd,
		&sub.CancelAtPeriodEnd, &sub.CanceledAt, &sub.CreatedAt, &sub.UpdatedAt,
	)
	return &sub, err
}

// UpdateSubscription updates a subscription
func (d *DB) UpdateSubscription(ctx context.Context, params UpdateSubscriptionParams) (*Subscription, error) {
	query := `
		UPDATE subscriptions
		SET status = $2,
		    current_period_start = $3,
		    current_period_end = $4,
		    cancel_at_period_end = $5,
		    canceled_at = $6,
		    updated_at = NOW()
		WHERE id = $1
		RETURNING id, user_id, stripe_customer_id, stripe_subscription_id, tier, status,
		          current_period_start, current_period_end, cancel_at_period_end, canceled_at,
		          created_at, updated_at
	`

	row := d.pool.QueryRow(ctx, query,
		params.ID, params.Status, params.CurrentPeriodStart,
		params.CurrentPeriodEnd, params.CancelAtPeriodEnd, params.CanceledAt)

	var sub Subscription
	err := row.Scan(
		&sub.ID, &sub.UserID, &sub.StripeCustomerID, &sub.StripeSubscriptionID,
		&sub.Tier, &sub.Status, &sub.CurrentPeriodStart, &sub.CurrentPeriodEnd,
		&sub.CancelAtPeriodEnd, &sub.CanceledAt, &sub.CreatedAt, &sub.UpdatedAt,
	)
	return &sub, err
}

// CancelSubscription marks a subscription as canceled
func (d *DB) CancelSubscription(ctx context.Context, id uuid.UUID) (*Subscription, error) {
	query := `
		UPDATE subscriptions
		SET status = 'canceled',
		    canceled_at = NOW(),
		    updated_at = NOW()
		WHERE id = $1
		RETURNING id, user_id, stripe_customer_id, stripe_subscription_id, tier, status,
		          current_period_start, current_period_end, cancel_at_period_end, canceled_at,
		          created_at, updated_at
	`

	row := d.pool.QueryRow(ctx, query, id)

	var sub Subscription
	err := row.Scan(
		&sub.ID, &sub.UserID, &sub.StripeCustomerID, &sub.StripeSubscriptionID,
		&sub.Tier, &sub.Status, &sub.CurrentPeriodStart, &sub.CurrentPeriodEnd,
		&sub.CancelAtPeriodEnd, &sub.CanceledAt, &sub.CreatedAt, &sub.UpdatedAt,
	)
	return &sub, err
}

// CreateBillingEvent creates a billing event log entry
func (d *DB) CreateBillingEvent(ctx context.Context, event BillingEvent) error {
	query := `
		INSERT INTO billing_events (user_id, stripe_event_id, event_type, event_data)
		VALUES ($1, $2, $3, $4)
	`

	_, err := d.pool.Exec(ctx, query,
		event.UserID, event.StripeEventID, event.EventType, event.EventData)
	return err
}

// GetDailyScanUsage retrieves the scan count for a user on a specific date
func (d *DB) GetDailyScanUsage(ctx context.Context, userID uuid.UUID, date time.Time) (int, error) {
	query := `
		SELECT scan_count
		FROM daily_scan_usage
		WHERE user_id = $1 AND scan_date = $2
	`

	var count int
	err := d.pool.QueryRow(ctx, query, userID, date).Scan(&count)
	if err != nil {
		// No record means 0 scans
		return 0, nil
	}
	return count, nil
}

// IncrementDailyScanCount increments the scan count for a user
func (d *DB) IncrementDailyScanCount(ctx context.Context, userID uuid.UUID) (int, error) {
	query := `
		INSERT INTO daily_scan_usage (user_id, scan_date, scan_count)
		VALUES ($1, CURRENT_DATE, 1)
		ON CONFLICT (user_id, scan_date)
		DO UPDATE SET
			scan_count = daily_scan_usage.scan_count + 1,
			updated_at = NOW()
		RETURNING scan_count
	`

	var count int
	err := d.pool.QueryRow(ctx, query, userID).Scan(&count)
	return count, err
}

// CheckScanLimit checks if a user has exceeded their daily scan limit
func (d *DB) CheckScanLimit(ctx context.Context, userID uuid.UUID, tier string) (bool, error) {
	query := `
		SELECT check_scan_limit($1, $2)
	`

	var allowed bool
	err := d.pool.QueryRow(ctx, query, userID, tier).Scan(&allowed)
	return allowed, err
}

